// Extract message from webhook body
const body = $input.first().json.body || $input.first().json;
const chatInput = body.chatInput || body.message || '';
const sessionId = body.sessionId || 'default';

return [{
  json: {
    chatInput: chatInput,
    sessionId: sessionId
  }
}];

// Check if the AI response contains an order confirmation
const aiResponse = $input.first().json.output || $input.first().json.text || '';

const orderMatch = aiResponse.match(/\[ORDER_CONFIRMED\](.*?)\[\/ORDER_CONFIRMED\]/s);

if (orderMatch) {
  try {
    const orderData = JSON.parse(orderMatch[1]);
    const orderId = 'ORD-' + Date.now();

    // Clean response for customer (remove order tags)
    const cleanResponse = aiResponse.replace(/\[ORDER_CONFIRMED\].*?\[\/ORDER_CONFIRMED\]/s, '').trim();

    return [{
      json: {
        hasOrder: true,
        orderId: orderId,
        orderData: orderData,
        response: cleanResponse,
        timestamp: new Date().toISOString()
      }
    }];
  } catch (e) {
    return [{
      json: {
        hasOrder: false,
        response: aiResponse,
        error: e.message
      }
    }];
  }
}

return [{
  json: {
    hasOrder: false,
    response: aiResponse
  }
}];

